INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'c0b47a3b-452e-4249-ad28-a1a210263939',
  '00000000-0000-0000-0000-000000000001',
  $escape$Polars GroupBy + Join — The Pandas Patterns You Already Know, Rewritten$escape$,
  $escape$Polars shares Pandas' core abstractions — DataFrame, Series, groupby, join — but the API is expression-based and lazy-first. There's no index. Rows are accessed by position or filtered by expression, never by label. `df.select()` and `df.filter()` replace `.loc[]` and `.iloc[]`.

GroupBy returns an intermediate that takes expressions, not lambdas: `df.group_by('team').agg(pl.col('score').mean())` is the Polars equivalent of `df.groupby('team')['score'].mean()`. The key difference: you can pack multiple aggregations into a single `.agg()` call without renaming gymnastics.

Joins use `df.join(other, on='key', how='inner')` — same semantics as Pandas `merge()`, but Polars defaults to suffix `_right` and doesn't create a MultiIndex. For non-equi joins, use `.join_where()`.

Series is a single typed column. Unlike Pandas, there's no implicit type coercion — a `pl.Int64` Series rejects strings at insertion, not at query time. This strictness catches bugs earlier and keeps lazy query plans optimizable.$escape$,
  $escape$import polars as pl

df = pl.DataFrame({
    "team": ["a", "a", "b", "b"],
    "score": [10, 20, 30, 40],
    "bonus": [1, 2, 3, 4],
})

# groupby with multiple aggs in one call
result = df.group_by("team").agg(
    pl.col("score").mean().alias("avg_score"),
    pl.col("bonus").sum().alias("total_bonus"),
)

# join two frames on a shared key
lookup = pl.DataFrame({"team": ["a", "b"], "region": ["US", "EU"]})
joined = result.join(lookup, on="team", how="inner")
print(joined)$escape$,
