INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'e12de35b-e394-45bb-a2fb-69483dd36cfd',
  '00000000-0000-0000-0000-000000000001',
  $escape$Polars in Jupyter — Reproducible Notebooks with Parameterized LazyFrames$escape$,
  $escape$Jupyter notebooks rot fast when DataFrames are executed out of order. Polars' lazy API is your best defense: build the entire query plan declaratively, then call .collect() in a single cell at the end. This makes cell execution order irrelevant to correctness.

For parameterized notebooks, define all config in cell one — file paths, filter thresholds, date ranges — then reference them inside pl.scan_parquet() and .filter() expressions. Papermill can inject these parameters at runtime for batch runs.

Key practices: (1) Always use scan_* over read_* so the query plan stays lazy until you explicitly collect. (2) Pin your polars version with %pip install polars==1.30.0 in the first cell. (3) Use .explain() to inspect the optimized plan before collecting — this is your notebook's 'dry run'. (4) Avoid intermediate .collect() calls mid-pipeline; they break predicate pushdown and projection pushdown optimizations. (5) Serialize final results with .sink_parquet() for reproducible artifacts.$escape$,
  $escape$import polars as pl

# Cell 1: Parameters (Papermill-injectable)
DATA_PATH = "s3://lake/events.parquet"
MIN_SCORE = 0.8
DATE_FROM = "2026-01-01"

# Cell 2: Lazy query plan
q = (
    pl.scan_parquet(DATA_PATH)
    .filter(pl.col("score") >= MIN_SCORE)
    .filter(pl.col("created_at") >= pl.lit(DATE_FROM).str.to_datetime())
    .group_by("category")
    .agg(pl.col("score").mean().alias("avg_score"))
)

print(q.explain())  # inspect optimized plan
result = q.collect()$escape$,
  $escape$python$escape$,
