INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '8b5cefd5-8ac2-43c8-8cf3-f2854f3e94d5',
  '00000000-0000-0000-0000-000000000001',
  $escape$Polars Lazy + Streaming — Process 50GB Files on 8GB RAM$escape$,
  $escape$Polars' lazy API doesn't just defer execution — it enables streaming mode, which processes data in batches without loading the full dataset into memory. This is the key to handling files larger than your available RAM.

When you call .collect(streaming=True) on a LazyFrame, Polars breaks the query into pipeline-friendly chunks, applies predicate pushdown and projection pushdown per chunk, and never materializes the full intermediate result. This means a group_by aggregation on a 50GB Parquet file can run on a laptop with 8GB RAM.

Critical detail: not all operations support streaming. Joins and sorts that require global ordering will force a full materialization. Use .explain(streaming=True) to inspect whether Polars actually streams your plan — look for STREAMING in the output.

For maximum throughput, pair streaming with scan_parquet's row_index and hive_partitioning options to skip irrelevant row groups entirely. Predicate pushdown on partitioned Parquet means Polars never reads data it doesn't need — zero wasted I/O at the storage layer.$escape$,
  $escape$import polars as pl

# Lazy scan — nothing read yet
q = (
    pl.scan_parquet("events/**/*.parquet", hive_partitioning=True)
    .filter(pl.col("event_date") >= "2025-01-01")
    .group_by("user_id")
    .agg(
        pl.col("duration_ms").mean().alias("avg_duration"),
        pl.col("event_id").count().alias("event_count"),
    )
)

# Verify streaming is used
print(q.explain(streaming=True))

# Execute in streaming mode — constant memory
result = q.collect(streaming=True)$escape$,
  $escape$python$escape$,
