INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'abf5110a-1454-403f-b14b-4cf2f1a31e84',
  '00000000-0000-0000-0000-000000000001',
  $escape$Polars Time Series — Lag Features and Rolling Windows Without the Pandas Baggage$escape$,
  $escape$Polars handles time series natively through its expression API, not bolted-on methods. The group_by_dynamic method replaces pandas resample — pass every="1h" to bucket timestamps, then aggregate with any expression. For rolling windows, shift from .rolling() on a Series to .rolling_mean(window_size="7d") directly in a select or with_columns context, keyed by a sorted datetime column using by parameter. Lag features are just .shift(n) inside expressions — chain multiple shifts to build autoregressive feature sets in a single with_columns call without intermediate DataFrames. Seasonality extraction uses .dt.hour(), .dt.day_of_week(), or .dt.month() as categorical encoders. The critical Polars advantage: all of these compose lazily. A LazyFrame pipeline that resamples, adds 5 lag columns, computes a 30-day rolling std, and extracts day-of-week executes in one optimized pass. No copies, no index alignment bugs. Sort your time column first — group_by_dynamic requires it and won't warn you clearly if you forget.$escape$,
  $escape$import polars as pl

df = pl.scan_csv("timeseries.csv").with_columns(
    pl.col("timestamp").str.to_datetime()
).sort("timestamp")

features = df.with_columns(
    pl.col("value").shift(1).alias("lag_1"),
    pl.col("value").shift(7).alias("lag_7"),
    pl.col("value").rolling_mean(window_size=7).alias("roll_7d_mean"),
    pl.col("value").rolling_std(window_size=30).alias("roll_30d_std"),
    pl.col("timestamp").dt.weekday().alias("day_of_week"),
    pl.col("timestamp").dt.hour().alias("hour"),
).drop_nulls().collect()$escape$,
  $escape$python$escape$,
