INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '7215b39c-44bf-4c51-ac70-03646c15ea5a',
  '00000000-0000-0000-0000-000000000001',
  $escape$Polars Reproducibility — Seeds, Pinning, and Escaping Notebooks$escape$,
  $escape$Polars uses a streaming, multi-threaded engine that can reorder operations across threads. This means reproducibility requires more than just setting a Python random seed. First, pin your polars version exactly (`polars==1.30.0` in requirements.txt, not `>=`). Minor releases can change query optimizer behavior, altering row order in joins and group-bys. For deterministic row ordering, always end pipelines with an explicit `.sort()` — Polars makes zero guarantees about output order otherwise.

For random sampling, `df.sample(n=100, seed=42)` is reproducible within the same polars version, but cross-version stability isn't promised. When converting notebooks to scripts, extract your LazyFrame pipeline into a function returning a `LazyFrame`, then call `.collect()` once at the boundary. This avoids the notebook anti-pattern of repeatedly collecting intermediate DataFrames, which obscures which materialization produced your result. Lock your environment with `uv pip compile` and commit the lockfile. Reproducibility in Polars is deterministic ordering plus version pinning — the engine won't do it for you.$escape$,
  $escape$import polars as pl

def build_pipeline(path: str, seed: int = 42) -> pl.LazyFrame:
    return (
        pl.scan_parquet(path)
        .filter(pl.col("score") > 0.5)
        .with_columns(pl.col("score").rank().alias("rank"))
        .sort("rank")  # explicit order for reproducibility
    )

def sample_reproducible(df: pl.DataFrame, n: int = 100) -> pl.DataFrame:
    return df.sample(n=n, seed=42)

# Single collect at the boundary
result = build_pipeline("data/features.parquet").collect()
sampled = sample_reproducible(result)$escape$,
  $escape$python$escape$,
